class Solution:
    def trap(self, height):
        n = len(height)
        total = 0
        for i in range(n):
            left = max(height[:i + 1])
            right = max(height[i:])
            total += min(left, right) - height[i]
        return total

solutions.python:
class Solution:
    def trap(self, height):
        l, r = 0, len(height) - 1
        left_max = right_max = 0
        total = 0
        while l < r:
            if height[l] < height[r]:
                left_max = max(left_max, height[l])
                total += left_max - height[l]
                l += 1
            else:
                right_max = max(right_max, height[r])
                total += right_max - height[r]
                r -= 1
        return total

